import React, { useState } from "react";
import "../styles/Purpose.css";
import { useNavigate } from "react-router-dom";

function Purpose() {
  const navigate = useNavigate();
  const [selectedPurposes, setSelectedPurposes] = useState([]);

  const purposes = [
    { id: "anxiety", label: "Anxiety", icon: "😰" },
    { id: "depression", label: "Depression", icon: "😢" },
    { id: "stress", label: "Stress", icon: "😫" },
    { id: "sleep", label: "Sleep Issues", icon: "😴" },
    { id: "relationships", label: "Relationships", icon: "❤️" },
    { id: "self-esteem", label: "Self-Esteem", icon: "💪" },
    { id: "addiction", label: "Addiction", icon: "🚫" },
    { id: "general", label: "General Chat", icon: "💬" },
  ];

  const handlePurposeClick = (id) => {
    setSelectedPurposes((prev) =>
      prev.includes(id)
        ? prev.filter((p) => p !== id)
        : [...prev, id]
    );
  };

  const handleContinue = () => {
    // Navigate to dashboard after selecting purposes
    navigate("/dashboard");
  };

  return (
    <div className="purpose-wrapper">
      <div className="purpose-card">
        <h2>What brings you here today?</h2>
        <p>Select all that apply to personalize your experience</p>

        <div className="purpose-grid">
          {purposes.map((purpose) => (
            <div
              key={purpose.id}
              className={`purpose-option ${
                selectedPurposes.includes(purpose.id) ? "active" : ""
              }`}
              onClick={() => handlePurposeClick(purpose.id)}
            >
              <span>{purpose.icon}</span>
              <p>{purpose.label}</p>
            </div>
          ))}
        </div>

        <button
          className="purpose-btn"
          onClick={handleContinue}
          disabled={selectedPurposes.length === 0}
        >
          Continue to Dashboard
        </button>
      </div>
    </div>
  );
}

export default Purpose;
